import{_ as e,o as a,c as d,a2 as i}from"./chunks/framework.C_beXv0I.js";const m=JSON.parse('{"title":"CLI commands","description":"","frontmatter":{},"headers":[],"relativePath":"reference/commands.md","filePath":"reference/commands.md","lastUpdated":1783011651000}'),o={name:"reference/commands.md"};function s(r,t,n,c,l,h){return a(),d("div",null,[...t[0]||(t[0]=[i(`<h1 id="cli-commands" tabindex="-1">CLI commands <a class="header-anchor" href="#cli-commands" aria-label="Permalink to &quot;CLI commands&quot;">​</a></h1><p>The <code>muster</code> CLI is plain Node ESM. It makes <strong>no model calls</strong>. Every verb does deterministic work and prints JSON you can read or pipe. This is the layer that makes routing reproducible.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @adnova-group/muster</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">comman</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">d</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> [args]</span></span></code></pre></div><h2 id="routing-and-capabilities" tabindex="-1">Routing and capabilities <a class="header-anchor" href="#routing-and-capabilities" aria-label="Permalink to &quot;Routing and capabilities&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><code>detect</code></td><td>Sniff the current project: languages, shape, greenfield flag.</td></tr><tr><td><code>capabilities</code></td><td>Walk the resolution ladder for every role; report the winner, full fallback chain, recommendations, and model.</td></tr><tr><td><code>match &lt;task&gt;</code></td><td>Rank every catalog provider against a free-text task by deterministic token overlap.</td></tr><tr><td><code>route &lt;outcome&gt;</code></td><td>Resolve which pipeline an outcome routes to.</td></tr><tr><td><code>domain &lt;outcome&gt;</code></td><td>Classify an outcome into a domain (pm, business, content, ops, software).</td></tr><tr><td><code>pipeline &lt;id|domain&gt;</code></td><td>Show the resolved pipeline definition.</td></tr></tbody></table><h2 id="planning-and-orchestration" tabindex="-1">Planning and orchestration <a class="header-anchor" href="#planning-and-orchestration" aria-label="Permalink to &quot;Planning and orchestration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><code>manifest validate &lt;file&gt;</code></td><td>Validate a Crew Manifest&#39;s shape.</td></tr><tr><td><code>wave &lt;file&gt;</code></td><td>Compute dependency-ordered execution waves from a manifest.</td></tr><tr><td><code>next &lt;manifest.json&gt; [--done a,b]</code></td><td>Single-agent driver: given completed task ids, return the next runnable task (and the full ready frontier).</td></tr><tr><td><code>plan-checklist &lt;file&gt;</code></td><td>Render the plan as a checklist (<code>--done &lt;ids&gt;</code> ticks completed tasks).</td></tr><tr><td><code>tally &lt;file&gt;</code> / <code>pick &lt;file&gt;</code></td><td>Tally tournament votes; pick selects the single best candidate (fallback ranker -- fuse is the default synthesis path).</td></tr><tr><td><code>fuse &lt;candidates.json&gt; &lt;fusion-map.json&gt;</code></td><td>Fusion decision engine: validates the debate map, applies the agreement gate, and either selects top-K candidates for synthesis (mode <code>fuse</code>) or falls back to the single best candidate (mode <code>fallback</code>). Deterministic, no LLM calls.</td></tr><tr><td><code>advise &lt;advice-request.json&gt;</code></td><td>Validate an advice request and emit the structured advisor dispatch input (<code>advisorModel</code> + <code>request</code>). Deterministic, no LLM calls. The advisor role resolves to the peak tier (fable, degrading to opus when fable is disabled).</td></tr></tbody></table><h2 id="scoring-and-prioritization" tabindex="-1">Scoring and prioritization <a class="header-anchor" href="#scoring-and-prioritization" aria-label="Permalink to &quot;Scoring and prioritization&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><code>score &lt;file&gt;</code></td><td>Score an artifact against a gate using the floor principle.</td></tr><tr><td><code>humanize-score &lt;file&gt; [--threshold N]</code></td><td>Deterministic 0–100 AI-tell score for human-facing text (no LLM); the CI-gateable measure behind the humanizer rewrite. Reads stdin when the arg is <code>-</code> or absent.</td></tr><tr><td><code>prioritize &lt;file&gt; [--model rice|ice|wsjf|weighted]</code></td><td>Rank initiatives deterministically. See below.</td></tr></tbody></table><h3 id="prioritization-models" tabindex="-1">Prioritization models <a class="header-anchor" href="#prioritization-models" aria-label="Permalink to &quot;Prioritization models&quot;">​</a></h3><p><code>prioritize</code> does the arithmetic; the model only supplies the factor estimates. Given the same inputs, the same ranking. Every model fails loud on non-finite, non-positive, or zero-denominator inputs.</p><table tabindex="0"><thead><tr><th>Model</th><th>Formula</th><th>Item fields</th></tr></thead><tbody><tr><td><code>rice</code> (default)</td><td><code>(reach × impact × confidence) / effort</code></td><td><code>reach</code>, <code>impact</code>, <code>confidence</code>, <code>effort</code></td></tr><tr><td><code>ice</code></td><td><code>impact × confidence × ease</code></td><td><code>impact</code>, <code>confidence</code>, <code>ease</code></td></tr><tr><td><code>wsjf</code></td><td><code>costOfDelay / jobSize</code></td><td><code>costOfDelay</code>, <code>jobSize</code></td></tr><tr><td><code>weighted</code></td><td><code>Σ (weightᵢ × scoreᵢ)</code></td><td><code>criteria: [{ weight, score }]</code></td></tr></tbody></table><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># rank a JSON file of initiatives with WSJF</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @adnova-group/muster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prioritize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> initiatives.json</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wsjf</span></span></code></pre></div><p>The input file is either an array of items or <code>{ &quot;items&quot;: [...], &quot;model&quot;: &quot;wsjf&quot; }</code>. A <code>--model</code> flag overrides the file&#39;s <code>model</code>.</p><h2 id="prompt-evaluation" tabindex="-1">Prompt evaluation <a class="header-anchor" href="#prompt-evaluation" aria-label="Permalink to &quot;Prompt evaluation&quot;">​</a></h2><p>Lint, eval, and optimize prompts an application generates to build agents/agentic workflows (or prompts found in a codebase). The deterministic core runs offline; a skill (<code>muster-prompt-smith</code>, the <code>prompt-quality</code> role) supplies the model calls for empirical eval.</p><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><code>prompt lint &lt;file&gt; [--agent] [--tools] [--system] [--tool-schema &lt;f&gt;] [--chat &lt;f&gt;] [--workflow &lt;f&gt;]</code></td><td>Lint prompt structure + guardrails against Anthropic&#39;s best practices (no LLM). Returns a scored rubric and <code>findings[]</code> with source-cited rule ids. <code>--tool-schema</code> passes real tool schemas so the schema↔intent rule checks each tool + its required fields; <code>--chat</code> lints a multi-turn chat for role-ordering / role-bleed; <code>--workflow</code> lints a multi-prompt workflow for context-boundary erosion. Reads stdin when the file arg is <code>-</code> or absent.</td></tr><tr><td><code>prompt variations &lt;file&gt; [--agent] [--tools] [--system]</code></td><td>Emit deterministic, technique-driven prompt variations, each closing a specific lint gap.</td></tr><tr><td><code>prompt eval &lt;suite.json&gt;</code></td><td>Grade a suite of pre-collected outputs: code graders (<code>json</code>/<code>regex</code>/<code>python</code>/<code>tool-call</code>/<code>trajectory</code>) combined with the model-judge score; reports per-case <code>score</code>, <code>accuracy</code>, <code>averageScore</code>.</td></tr><tr><td><code>prompt optimize &lt;file.json&gt;</code></td><td>Select the winning variation from scored candidates via the tournament floor; flags a <code>regression</code> when no variation beats the pinned baseline.</td></tr><tr><td><code>prompt scan &lt;dir&gt;</code></td><td>Walk a repo for candidate prompts (<code>.prompt</code> files, <code>prompts/</code> dirs, backtick <code>system</code>/<code>prompt</code>/<code>instructions</code> assignments) and lint each. Returns per-prompt findings + a pass/fail summary. Powers the conditional <code>prompt-quality</code> audit dimension.</td></tr></tbody></table><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># lint a runtime agent prompt piped from your app</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">your-app</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --print-agent-prompt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @adnova-group/muster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> prompt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lint</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --agent</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tools</span></span></code></pre></div><p>The linter enforces the structure (role, XML tags, multishot examples, explicit output format, positive framing) and the agent/guardrail rules (imperative tool framing, stop conditions, &quot;I don&#39;t know&quot; allowance, citations, input separation). Every finding cites the doc rule it comes from. Code in fenced/inline blocks is ignored across languages, so a <code>never</code> keyword or <code>\${x}</code> in an example is not mistaken for an instruction.</p><p>The rubric is genre-aware: pass <code>--system</code> for an agent/skill <em>instruction</em> prompt (the action-verb-lead and multishot rules relax, and prohibitions are tolerated more) versus the default single-task rubric. A prompt that legitimately violates a rule can opt out inline with a comment — <code>&lt;!-- prompt-lint-disable ANTH-POS-001: reason --&gt;</code> — and the suppression is surfaced in the result. A prompt with zero findings scores a perfect 15/15.</p><h2 id="failure-first-and-review" tabindex="-1">Failure-first and review <a class="header-anchor" href="#failure-first-and-review" aria-label="Permalink to &quot;Failure-first and review&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><code>diagnose &lt;symptom&gt;</code></td><td>Structure a failure-first bug fix (<code>--ci &lt;file&gt;</code> to read CI output).</td></tr><tr><td><code>audit</code></td><td>Drive the whole-codebase review and fix across six dimensions (architecture, tech-debt, coverage, simplification, readability, security). When the project builds prompts/agents (an LLM/agent SDK dependency is present), a seventh <code>prompt-quality</code> dimension is added, backed by <code>prompt scan</code>.</td></tr><tr><td><code>issue &lt;ref&gt;</code></td><td>Resolve a GitHub issue reference into an outcome (title + body).</td></tr><tr><td><code>assess &lt;outcome&gt;</code></td><td>Deterministic gap-check: is the outcome clear enough to route?</td></tr><tr><td><code>steer &lt;message&gt;</code></td><td>Classify a mid-run steering message (approve, stop, status, retarget).</td></tr></tbody></table><h2 id="ops-and-setup" tabindex="-1">Ops and setup <a class="header-anchor" href="#ops-and-setup" aria-label="Permalink to &quot;Ops and setup&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><code>install [home]</code></td><td>Copy the output style and print the plugin-install steps.</td></tr><tr><td><code>uninstall [home]</code></td><td>Print the plugin-removal steps and clean up legacy style files.</td></tr><tr><td><code>setup [dir]</code></td><td>Scaffold Muster files into a target directory.</td></tr><tr><td><code>vendor</code></td><td>Generate built-in agents and skills from <code>vendor/manifest.yaml</code>.</td></tr><tr><td><code>doctor</code></td><td>Health-check the installation.</td></tr><tr><td><code>profile</code></td><td>Report the resolved provider profile.</td></tr><tr><td><code>signals [dir]</code></td><td>Surface project signals.</td></tr><tr><td><code>scratchpad &lt;runId&gt;</code></td><td>Read a run&#39;s scratchpad.</td></tr><tr><td><code>memory read</code> / <code>memory write ...</code></td><td>Read and write Muster&#39;s memory store.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Run any verb with no arguments to see its usage. The CLI fails loud with a clear message on bad input.</p></div>`,25)])])}const u=e(o,[["render",s]]);export{m as __pageData,u as default};
